changeSet.sql:
CREATE OR ALTER TRIGGER trg_projects_sync_organization_active_projects_count ON projects AFTER INSERT, UPDATE, DELETE AS BEGIN SET NOCOUNT ON;
DECLARE @affected_organizations TABLE ( organization_id UNIQUEIDENTIFIER PRIMARY KEY );
INSERT INTO @affected_organizations (organization_id) SELECT DISTINCT organization_id FROM inserted WHERE organization_id IS NOT NULL
UNION
SELECT DISTINCT organization_id FROM deleted WHERE organization_id IS NOT NULL;
UPDATE o SET active_projects_count = ISNULL(x.project_count, 0) FROM organizations o INNER JOIN @affected_organizations ao ON ao.organization_id = o.id LEFT JOIN ( SELECT p.organization_id, COUNT(*) AS project_count FROM projects p GROUP BY p.organization_id ) x ON x.organization_id = o.id; END;

CREATE OR ALTER TRIGGER trg_events_sync_organization_active_events_count ON events AFTER INSERT, UPDATE, DELETE AS BEGIN SET NOCOUNT ON;
DECLARE @affected_organizations TABLE ( organization_id UNIQUEIDENTIFIER PRIMARY KEY );
INSERT INTO @affected_organizations (organization_id) SELECT DISTINCT organization_id FROM inserted WHERE organization_id IS NOT NULL
UNION
SELECT DISTINCT organization_id FROM deleted WHERE organization_id IS NOT NULL;
UPDATE o SET active_events_count = ISNULL(x.event_count, 0) FROM organizations o INNER JOIN @affected_organizations ao ON ao.organization_id = o.id LEFT JOIN ( SELECT e.organization_id, COUNT(*) AS event_count FROM events e WHERE e.is_cancelled = 0 GROUP BY e.organization_id ) x ON x.organization_id = o.id; END;
